import React, { useState, useEffect, useRef } from 'react';
import { useNavigate } from 'react-router-dom';

export default function VerificationScreen() {
  const [code, setCode] = useState(['', '', '', '']);
  const [timer, setTimer] = useState(60);
  const [canResend, setCanResend] = useState(false);
  const [error, setError] = useState('');
  const inputs = useRef([]);
  const navigate = useNavigate();
  const auth = JSON.parse(localStorage.getItem('pizzaAuth') || '{}');

  useEffect(() => {
    if (!auth.phone) navigate('/login');
  }, []);

  useEffect(() => {
    if (timer <= 0) { setCanResend(true); return; }
    const id = setInterval(() => setTimer(t => t - 1), 1000);
    return () => clearInterval(id);
  }, [timer]);

  const handleChange = (idx, val) => {
    if (!/^\d?$/.test(val)) return;
    const next = [...code];
    next[idx] = val;
    setCode(next);
    if (val && idx < 3) inputs.current[idx + 1]?.focus();
  };

  const handleKeyDown = (idx, e) => {
    if (e.key === 'Backspace' && !code[idx] && idx > 0) {
      inputs.current[idx - 1]?.focus();
    }
  };

  const handleVerify = () => {
    if (code.join('').length < 4) {
      setError('הכנס 4 ספרות');
      return;
    }
    // Mock: any 4-digit code is accepted
    localStorage.setItem('pizzaAuth', JSON.stringify({ ...auth, verified: true }));
    navigate('/');
  };

  const handleResend = () => {
    setTimer(60);
    setCanResend(false);
    setCode(['', '', '', '']);
    setError('');
    inputs.current[0]?.focus();
  };

  return (
    <div className="max-w-sm mx-auto mt-16 p-8 bg-white rounded-2xl shadow-xl text-center">
      <div className="text-6xl mb-4">📱</div>
      <h2 className="text-2xl font-bold text-tomato mb-1">אימות מספר טלפון</h2>
      <p className="text-gray-500 text-sm mb-2">הכנס את הקוד בן 4 הספרות שנשלח אליך ב-SMS</p>
      {auth.phone && (
        <p className="text-gray-700 font-semibold mb-6" dir="ltr">{auth.phone}</p>
      )}

      <div className="flex gap-3 justify-center mb-5" dir="ltr">
        {code.map((digit, idx) => (
          <input
            key={idx}
            ref={el => (inputs.current[idx] = el)}
            type="text"
            inputMode="numeric"
            maxLength={1}
            value={digit}
            onChange={e => handleChange(idx, e.target.value)}
            onKeyDown={e => handleKeyDown(idx, e)}
            className="w-14 h-14 text-center text-2xl font-bold border-2 rounded-xl border-gray-300 focus:border-tomato focus:outline-none transition"
          />
        ))}
      </div>

      {error && <p className="text-red-500 text-sm mb-3">{error}</p>}

      <button
        onClick={handleVerify}
        className="w-full bg-tomato text-white py-3 rounded-xl font-bold text-lg hover:bg-red-700 transition mb-4"
      >
        אמת קוד
      </button>

      <p className="text-sm text-gray-500">
        {canResend ? (
          <button
            onClick={handleResend}
            className="text-tomato font-semibold hover:underline"
          >
            שלח קוד מחדש
          </button>
        ) : (
          <>שלח שוב בעוד <span className="font-bold text-tomato">{timer}</span> שניות</>
        )}
      </p>

      <button
        onClick={() => navigate('/login')}
        className="mt-4 text-sm text-gray-400 hover:text-gray-600"
      >
        שנה מספר טלפון
      </button>
    </div>
  );
}
